            <Col>
              <Card.Text>{card.back}</Card.Text>
            </Col>
          </Row>
          <Row className="d-flex flex-row-reverse">
            <Button onClick={() => {
              if (window.confirm("Delete card?")) handleDeleteCard(card.id)
            }} variant="danger" className="m-1"><Trash /></Button>
            <Button variant="secondary" className="m-1">Edit</Button>
          </Row>
        </Container>
      </Card>
    </div>
  );
}

export default ViewCard;
